  "habitat": [
    {
      "content": "Urbane Räume",
      "evidence_anchor": "Gardening interventions, however, offer more than simply contact with nature. They are usually social interventions, providing opportunities for people to interact with others."
    }
  ],
  "taxa": [],
  "biodiversity_level": [
    {
      "content": "Artenvielfalt",
      "evidence_anchor": "All studies reported beneficial effects of gardening-based interventions for people experiencing mental health difficulties. Benefits included significant reduction in symptoms of depression (Son et al., 2004; Stepney and Davis, 2004; Gonzalez et al., 2009, 2010, 2011a, b; Kam and Siu, 2010) and anxiety (Son et al., 2004; Stepney and Davis, 2004; Kam and Siu, 2010; Gonzalez et al., 2011b) and significant increase in attentional capacity (Rappe et al., 2008; Gonzalez et al., 2010) and self-esteem (Son et al., 2004)."
    },
    {
      "content": "Funktionelle Diversität",
      "evidence_anchor": "These quantitative findings were supported and extended by the results of qualitative analyses, which enabled a more in-depth exploration of the types of benefits perceived by clients. Key themes included emotional benefits such as reduced stress and improved mood (Rappe et al., 2008; Kam and Siu, 2010), social benefits such as the development of a social network and improved social skills (Kam and Siu, 2010; Gonzalez et al., 2011b), vocational benefits such as learning new skills and changing attitudes towards work (Stepney and Davis, 2004; Kam and Siu, 2010), physical benefits such as improved sleep and physical health (Rappe et al., 2008) and spiritual benefits such as feeling more connected to nature and fascinated by plants (Kam and Siu, 2010; Gonzalez et al., 2011a)."
    }
  ],
